// Worked focus: httpsts-express5-path-syntax — Author Express 5.2 string paths with named wildcards, braces, reserved characters, and supported path-to-regexp syntax.
// Evidence: httpsts-worked-http-server-ts-express-routing-paths-4
// Competency: httpsts-worked-http-server-ts-express-routing-paths-4.
// Case 1655: privacy-sensitive records API using conditional requests.
// Operating constraint: retain a screen-reader-readable decision trace.
// Changed case: abort during a dependency phase and preserve cleanup plus response ownership.
function worked_http_server_ts_express_routing_paths_4(method: string, path: string, wildcardParts: readonly string[]): { route: string; status: number } {
  const normalized = method.toUpperCase();
  if (normalized === "GET" && path === "/incidents/latest") {
    return { route: "GET /incidents/latest", status: 200 };
  }
  if (normalized === "GET" && wildcardParts.length === 1) {
    return { route: "GET /incidents/{*parts}", status: 200 };
  }
  return { route: "unmatched", status: 404 };
}

